  1	import React from 'react';
  2	
  3	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
  4	import {
  5	  BootableDeviceType,
  6	  DeviceType,
  7	} from '@kubevirt-utils/resources/vm/utils/boot-order/bootOrder';
  8	import {
  9	  Button,
 10	  DataList,
 11	  DataListCell,
 12	  DataListControl,
 13	  DataListDragButton,
 14	  DataListItem,
 15	  DataListItemCells,
 16	  DataListItemRow,
 17	  DragDrop,
 18	  Draggable,
 19	  Droppable,
 20	  Split,
 21	  SplitItem,
 22	} from '@patternfly/react-core';
 23	import { MinusCircleIcon } from '@patternfly/react-icons';
 24	
 25	import { BootOrderEmptyState } from './BootOrderEmptyState';
 26	import DeviceTypeIcon from './DeviceTypeIcon';
 27	
 28	export const BootOrderModalBody: React.FC<{
 29	  changeEditMode: (isEditMode: boolean) => void;
 30	  devices: BootableDeviceType[];
 31	  isEditMode: boolean;
 32	  onChange: (disks: BootableDeviceType[]) => void;
 33	}> = ({ changeEditMode, devices, isEditMode, onChange }) => {
 34	  const { t } = useKubevirtTranslation();
 35	
 36	  const reorder = (
 37	    list: BootableDeviceType[],
 38	    startIndex: number,
 39	    endIndex: number,
 40	  ): BootableDeviceType[] => {
 41	    const result = Array.from(list);
 42	    const [removed] = result.splice(startIndex, 1);
 43	    result.splice(endIndex, 0, removed);
 44	    return result;
 45	  };
 46	
 47	  const onDrop = (source, dest) => {
 48	    if (dest) {
 49	      const newBootableDevices = reorder(devices, source.index, dest.index).map(
 50	        (device, index) => ({
 51	          ...device,
 52	          value: { ...device.value, bootOrder: index + 1 },
 53	        }),
 54	      );
 55	      onChange(newBootableDevices);
 56	
 57	      return true; // Signal that this is a valid drop and not to animate the item returning home.
 58	    }
 59	  };
 60	
 61	  // Remove a bootOrder from a device by index.
 62	  const onDelete = (name: string) => {
 63	    const deviceToUpdate = devices.find((d) => d.value.name === name);
 64	
 65	    const newDevices = [
 66	      ...devices.filter((device) => device.value.name !== name),
 67	      { ...deviceToUpdate, value: { ...deviceToUpdate.value, bootOrder: undefined } },
 68	    ];
 69	
 70	    onChange(newDevices);
 71	  };
 72	
 73	  const showEmpty = devices.length === 0 && !isEditMode;
 74	
 75	  return (
 76	    <>
 77	      {showEmpty ? (
 78	        <BootOrderEmptyState
 79	          message={t(
 80	            'VirtualMachine will attempt to boot from disks by order of apearance in YAML file',
 81	          )}
 82	          onClick={() => {
 83	            changeEditMode(true);
 84	          }}
 85	          addItemDisabledMessage={t('All sources selected')}
 86	          addItemIsDisabled={devices.length === 0}
 87	          addItemMessage={t('Add source')}
 88	          title={t('No resource selected')}
 89	        />
 90	      ) : (
 91	        <>
 92	          <DragDrop onDrop={onDrop}>
 93	            <Droppable hasNoWrapper>
 94	              <DataList aria-label="draggable data list example">
 95	                {devices.map(({ type, value }, index) => (
 96	                  <Draggable hasNoWrapper key={value.name}>
 97	                    <DataListItem aria-labelledby={value.name} ref={React.createRef()}>
 98	                      <DataListItemRow>
 99	                        <DataListControl>
100	                          <DataListDragButton
101	                            aria-describedby="Press space or enter to begin dragging, and use the arrow keys to navigate up or down. Press enter to confirm the drag, or any other key to cancel the drag operation."
102	                            aria-label="Reorder"
103	                            aria-labelledby={value.name}
104	                            aria-pressed="false"
105	                          />
106	                        </DataListControl>
107	                        <DataListItemCells
108	                          dataListCells={[
109	                            <DataListCell key={value.name}>
110	                              <Split>
111	                                <SplitItem isFilled>
112	                                  <span id={value.name}>{value.name}</span>
113	
114	                                  <span className="pf-v6-u-ml-sm">
115	                                    <DeviceTypeIcon type={type as DeviceType} />
116	                                  </span>
117	                                </SplitItem>
118	                                <SplitItem>
119	                                  {index !== devices.length - 1 && (
120	                                    <Button
121	                                      className="kubevirt-boot-order__delete-btn"
122	                                      id={`${value.name}-delete-btn`}
123	                                      onClick={() => onDelete(value.name)}
124	                                      variant="link"
125	                                    >
126	                                      <MinusCircleIcon />
127	                                    </Button>
128	                                  )}
129	                                </SplitItem>
130	                              </Split>
131	                            </DataListCell>,
132	                          ]}
133	                        />
134	                      </DataListItemRow>
135	                    </DataListItem>
136	                  </Draggable>
137	                ))}
138	              </DataList>
139	            </Droppable>
140	          </DragDrop>
141	        </>
142	      )}
143	    </>
144	  );
145	};

